import { useState, useEffect } from 'react';

interface Comment {
  id: string;
  user: string;
  content: string;
  replies?: Comment[];
}

const CommentSection = ({ videoId }: { videoId: string }) => {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Simulate fetching comments
    setTimeout(() => {
      setComments([
        {
          id: '1',
          user: 'Jane Doe',
          content: 'Great video! Really enjoyed it.',
          replies: [
            {
              id: '1-1',
              user: 'John Smith',
              content: 'I agree, it was very informative!'
            }
          ]
        },
        {
          id: '2',
          user: 'Alice Johnson',
          content: 'Could you make a video on a related topic?'
        }
      ]);
      setLoading(false);
    }, 1000);
  }, [videoId]);

  const handleCommentSubmit = () => {
    if (newComment.trim()) {
      const newCommentObj: Comment = {
        id: (comments.length + 1).toString(),
        user: 'Current User',
        content: newComment,
      };
      setComments([newCommentObj, ...comments]);
      setNewComment('');
    }
  };

  if (loading) return <div className="text-gray-400">Loading comments...</div>;
  if (error) return <div className="text-red-500">Error loading comments: {error}</div>;

  return (
    <div className="bg-gray-950 p-4 rounded-xl shadow-md">
      <h3 className="text-white text-lg font-semibold mb-4">Comments</h3>
      <div className="mb-4">
        <textarea
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          className="w-full p-2 rounded-lg bg-gray-800 text-white border border-gray-700 focus:border-indigo-500 focus:outline-none"
          placeholder="Add a comment..."
        />
        <button
          onClick={handleCommentSubmit}
          className="mt-2 px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-500 transition"
        >
          Comment
        </button>
      </div>
      <ul className="space-y-4">
        {comments.map((comment) => (
          <li key={comment.id} className="bg-gray-800 p-3 rounded-lg">
            <div className="text-white font-medium">{comment.user}</div>
            <p className="text-gray-400 mt-1">{comment.content}</p>
            {comment.replies && (
              <ul className="mt-2 pl-4 border-l border-gray-700">
                {comment.replies.map((reply) => (
                  <li key={reply.id} className="mt-2">
                    <div className="text-white font-medium">{reply.user}</div>
                    <p className="text-gray-400">{reply.content}</p>
                  </li>
                ))}
              </ul>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
};

export default CommentSection;
